class Solution(object):
    def countDistinctIntegers(self, nums):
        result = set(nums)
        for num in nums:
            rev = 0
            n = num
            while n > 0:
                rev = rev * 10 + n % 10
                n //= 10
            result.add(rev)
        return len(result)
